import { MinusCircleOutlined, PlusCircleFilled } from '@ant-design/icons';
import React, { useState } from 'react';
import {  Card, Skeleton, Switch } from 'antd';
import { Button, Tooltip } from 'antd';


const CardItem: React.FC = () => {
  const [loading, setLoading] = useState<boolean>(true);
  const [Counter, setCounter] = useState<number>(1);

  const onChange = (checked: boolean) => {
    setLoading(!checked);
  };

  return (
    <>
      <Switch checked={!loading} onChange={onChange} />
      <Card className='CardItem'  active style={{ width: 340, marginTop: 16 }} loading={loading}>
      <span className='Card_Counter'>
        <Button  shape="circle" icon={<PlusCircleFilled />} onClick={()=>setCounter(v => v+1)} />
        <div className='Counter'>
          {Counter}
        </div>
        <Button  shape="circle" icon={<MinusCircleOutlined />} onClick={()=>setCounter(v => v > 0 ? v-1 : v)} />
      </span>
      <span className='Card_Img'>
      <img alt=''  src='../Product/Product.png' width={100}  />
      </span>
      <Skeleton loading={loading} avatar active>
        sss
        </Skeleton>
      </Card>

    </>
  );
};

export default CardItem;
